INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (1,'Avocado Toast','Toasted sourdough topped with smashed avocado, a perfectly poached egg, chili flakes, and a drizzle of olive oil.',32,'https://images.unsplash.com/photo-1525351484163-7529414344d8?w=640&h=480&fit=crop',420,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (2,'Fluffy Pancakes','A golden stack of thick, fluffy pancakes served with warm maple syrup and a dusting of powdered sugar.',28,'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=640&h=480&fit=crop',520,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (3,'Blueberry Pancakes','Buttermilk pancakes stacked high and topped with fresh blueberries. Sweet, fruity, and irresistible.',30,'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?w=640&h=480&fit=crop',540,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (4,'Eggs Benedict','A perfectly poached egg layered over silky smoked salmon on a toasted muffin, smothered in rich hollandaise sauce.',35,'https://images.unsplash.com/photo-1608039829572-78524f79c4c7?w=640&h=480&fit=crop',480,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (5,'Crispy Waffles','Two golden Belgian waffles with a crisp caramelized exterior, fresh blueberries, and warm maple syrup.',27,'https://images.unsplash.com/photo-1562376552-0d160a2f238d?w=640&h=480&fit=crop',510,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (6,'French Toast','Triangle-cut French toast, golden outside with a soft custardy interior, served with whipped cream and strawberries.',29,'https://images.unsplash.com/photo-1588484588657-0bbbee05132f?w=640&h=480&fit=crop',530,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (7,'Golden Fried Eggs','Farm-fresh eggs fried in butter until whites are set and yolks gloriously runny, on rustic toasted bread.',22,'https://images.unsplash.com/photo-1533089860892-a7c6f0a88666?w=640&h=480&fit=crop',300,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (8,'Smoothie Bowl','A thick acai smoothie bowl loaded with granola, banana, fresh kiwi, chia seeds, and a drizzle of honey.',25,'https://images.unsplash.com/photo-1494597564530-871f2b93ac55?w=640&h=480&fit=crop',350,'Breakfast') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (9,'Americano','A bold shot of espresso diluted with hot water, strong and unapologetically rich.',8,'https://images.unsplash.com/photo-1587985782608-20062892559d?w=640&h=480&fit=crop',5,'Drinks') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (10,'Flat White','Double ristretto espresso topped with velvety microfoam milk. Intense, creamy, and perfectly balanced.',12,'https://images.unsplash.com/photo-1611564494260-6f21b80af7ea?w=640&h=480&fit=crop',120,'Drinks') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (11,'Chinese Black Tea','A ruby-red tea served alongside a handcrafted clay teapot on a bamboo tray. Earthy, smooth, and ceremonial.',6,'https://images.unsplash.com/photo-1558160074-4d7d8bdf4256?w=640&h=480&fit=crop',2,'Drinks') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (12,'Herbal Tea','A golden floral tea blooming with dried chrysanthemum, lavender buds, and rose hips. Fragrant and healing.',7,'https://images.unsplash.com/photo-1514733670139-4d87a1941d55?w=640&h=480&fit=crop',5,'Drinks') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (13,'Fresh Orange Juice','Bright orange juice garnished with fresh orange wedges. Naturally sweet and vibrantly refreshing.',14,'https://images.unsplash.com/photo-1641659735894-45046caad624?w=640&h=480&fit=crop',110,'Drinks') ON CONFLICT (id) DO NOTHING;
