INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (16,'Mocktail Trio','Three vibrant alcohol-free cocktails — pineapple cherry blend, lime mojito, and dragon fruit cooler.',18,'https://images.unsplash.com/photo-1551024709-8f23befc6f87?w=640&h=480&fit=crop',150,'Drinks') ON CONFLICT (id) DO NOTHING;
INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (17,'Wok Fried Rice','Golden fried rice with green peas, sweet corn, diced carrots, and tender chicken. Hearty and satisfying.',45,'https://images.unsplash.com/photo-1603133872878-684f208fb84b?w=640&h=480&fit=crop',550,'Rice') ON CONFLICT (id) DO NOTHING;
