INSERT INTO menu (id,name,description,price,image,calorie,category) VALUES (19,'Chicken Biryani','Fragrant saffron basmati rice in a copper handi with caramelized onions and curry leaves, served with rich gravy.',48,'https://images.unsplash.com/photo-1563379091339-03b21ab4a4f8?w=640&h=480&fit=crop',650,'Rice') ON CONFLICT (id) DO NOTHING;
